### Full Webpack Configuration with PosthogWebpackPlugin

Source: https://github.com/posthog/posthog-js/blob/main/packages/webpack-plugin/README.md

Presents a comprehensive Webpack configuration example that includes the PosthogWebpackPlugin. This setup configures the build mode, entry point, output, and extensively details the PosthogWebpackPlugin with options such as host, log level, and detailed source map settings, pulling project name and version from package.json.

```typescript
import path from 'node:path'
import webpack from 'webpack'
import { PosthogWebpackPlugin } from '@posthog/webpack-plugin'
import packageJson from './package.json'

const config: webpack.Configuration = {
    mode: 'production',
    entry: './src/index.ts',
    output: {
        filename: 'bundle.js',
        path: path.resolve(__dirname, 'dist'),
    },
    plugins: [
        new PosthogWebpackPlugin({
            personalApiKey: process.env.POSTHOG_PERSONAL_API_KEY,
            envId: process.env.POSTHOG_PROJECT_ID,
            host: process.env.POSTHOG_API_HOST,
            logLevel: 'error',
            sourcemaps: {
                enabled: true,
                project: packageJson.name,
                version: packageJson.version,
                deleteAfterUpload: true,
            },
        }),
    ],
}

export default config

```

